        if (_token == address(0)) revert ZeroAddress();
        token = IERC20(_token);
        selfRegistry = ISelfAgentRegistry(_selfRegistry);
    }

    /// @notice Verify that msg.sender is an agent wallet linked to a 
    ///         human-backed Self identity with a valid proof.
    /// @param agentId The Self Agent ID that msg.sender claims to be.
    modifier onlyVerifiedAgent(uint256 agentId) {
        // 1. The agent wallet registered on Self must be msg.sender
        if (selfRegistry.getAgentWallet(agentId) != msg.sender) 
            revert NotVerifiedAgent();
        // 2. The agent must have a valid human proof
        if (!selfRegistry.hasHumanProof(agentId)) 
            revert NotVerifiedAgent();
        _;
    }
}
```

Then gate `createLoanRequest`:

```solidity
function createLoanRequest(
    uint256 amount, 
    uint256 repayAmount, 
    uint256 deadline, 
    address lender,
    uint256 agentId          // <-- new parameter
)
    external
    onlyVerifiedAgent(agentId)  // <-- new modifier
    returns (uint256 loanId)
{
    // ... rest unchanged
}
```

## The Full Flow

```
1. Human verifies with Self.xyz → SBT minted, agentId created
2. Human calls setAgentWallet(agentId, agentWallet, deadline, sig)
   → Registry links agentWallet to the human's identity
3. Agent calls createLoanRequest(..., agentId)
   → Lending contract reads selfRegistry.getAgentWallet(agentId)
   → Confirms it equals msg.sender
   → Reads selfRegistry.hasHumanProof(agentId)
   → Confirms the agent has valid human backing
   → Loan request proceeds
```

No intermediate registration step, no extra mapping in your contract, no trust assumptions. The lending contract verifies the full chain directly against the Self registry in a single transaction.

The only addition to the existing UX is that the agent needs to pass its `agentId` when requesting a loan — which it already knows from the deployment flow.

