///         queryable via view functions — no indexer or database required.
///         All loans are denominated in a single ERC-20 token set at deployment.
contract AgentMicrolending {
    using SafeERC20 for IERC20;

    // ──────────────────────────────────────────────
    //  Types
    // ──────────────────────────────────────────────

    enum LoanStatus {
        Open,
        Funded,
        Repaid,
        Defaulted,
        Cancelled
