     1→"use client";
     2→
     3→import { useState } from "react";
     4→import { useAccount, useSendTransaction, useWriteContract } from "wagmi";
     5→import { parseEther } from "viem";
     6→import { SelfVerification } from "@/components/self-verification";
     7→import { LendingDashboard } from "@/components/lending-dashboard";
     8→
     9→// Self Agent Registry on Celo mainnet
    10→const REGISTRY_ADDRESS =
    11→  "0x62E37d0f6c5f67784b8828B3dF68BCDbB2e55095" as const;
    12→
    13→const REGISTRY_ABI = [
    14→  {
    15→    name: "setAgentWallet",
    16→    type: "function",
    17→    stateMutability: "nonpayable",
    18→    inputs: [
    19→      { name: "agentId", type: "uint256" },
    20→      { name: "newWallet", type: "address" },
    21→      { name: "deadline", type: "uint256" },
    22→      { name: "signature", type: "bytes" },
    23→    ],
    24→    outputs: [],
    25→  },
    26→] as const;
    27→
    28→const STEPS = [
    29→  { id: "deploy", label: "Deploy Agent" },
    30→  { id: "verify", label: "Verify Identity" },
    31→  { id: "delegate", label: "Delegate" },
    32→  { id: "fund", label: "Fund Agent" },
    33→  { id: "monitor", label: "Monitor" },
    34→] as const;
    35→
    36→type Step = (typeof STEPS)[number]["id"];
    37→
    38→const labelClass =
    39→  "font-mono text-xs uppercase tracking-[0.15em] text-ink-lighter";
    40→const inputClass =
    41→  "w-full border-b border-cream-dark bg-transparent px-0 py-2 text-sm text-ink placeholder:text-ink-lighter focus:border-ink focus:outline-none";
    42→
    43→export function DeployAgent() {
    44→  const { address } = useAccount();
    45→  const { sendTransactionAsync } = useSendTransaction();
    46→  const { writeContractAsync } = useWriteContract();
    47→  const [step, setStep] = useState<Step>("deploy");
    48→  const [isVerified, setIsVerified] = useState(false);
    49→  const [isDelegated, setIsDelegated] = useState(false);
    50→  // With EIP-7702, walletAddress (Privy EOA) IS the smart account address
    51→  const [agentAddress, setAgentAddress] = useState<string | null>(null);
    52→  const [walletId, setWalletId] = useState<string | null>(null);
    53→  const [agentId, setAgentId] = useState<number | null>(null);
    54→  const [deploying, setDeploying] = useState(false);
    55→  const [delegating, setDelegating] = useState(false);
    56→  const [agentName, setAgentName] = useState("");
    57→  const [fundAmount, setFundAmount] = useState("");
    58→  const [funding, setFunding] = useState(false);
    59→  const [funded, setFunded] = useState(false);
    60→
    61→  const handleDeploy = async () => {
    62→    if (!agentName.trim()) return;
    63→    setDeploying(true);
    64→    try {
    65→      const res = await fetch("/api/agent/deploy", {
    66→        method: "POST",
    67→        headers: { "Content-Type": "application/json" },
    68→        body: JSON.stringify({ agentName: agentName.trim() }),
    69→      });
    70→      const data = await res.json();
    71→      if (data.error) throw new Error(data.error);
    72→
    73→      setWalletId(data.walletId);
    74→      // EIP-7702: EOA address = smart account address
    75→      setAgentAddress(data.walletAddress);
    76→      setStep("verify");
    77→    } catch (err) {
    78→      console.error("Deploy failed:", err);
    79→    } finally {
    80→      setDeploying(false);
    81→    }
    82→  };
    83→
    84→  const handleVerificationSuccess = (
    85→    _agentAddr: string,
    86→    selfAgentId?: number
    87→  ) => {
    88→    setIsVerified(true);
    89→    if (selfAgentId != null) {
    90→      setAgentId(selfAgentId);
    91→    }
    92→    setStep("delegate");
    93→  };
    94→
    95→  const handleDelegate = async () => {
    96→    if (!address || agentId == null || !walletId || !agentAddress) return;
    97→    setDelegating(true);
    98→    try {
    99→      // 1. Backend signs EIP-712 with Privy agent wallet (the EOA that IS the smart account)
   100→      const res = await fetch("/api/agent-id/delegate", {
   101→        method: "POST",
   102→        headers: { "Content-Type": "application/json" },
   103→        body: JSON.stringify({
   104→          agentId,
   105→          walletId,
   106→          walletAddress: agentAddress,
   107→          ownerAddress: address,
   108→        }),
   109→      });
   110→      const data = await res.json();
   111→      if (data.error) throw new Error(data.error);
   112→
   113→      // 2. Human submits setAgentWallet tx on the Self registry
   114→      await writeContractAsync({
   115→        address: REGISTRY_ADDRESS,
   116→        abi: REGISTRY_ABI,
   117→        functionName: "setAgentWallet",
   118→        args: [
   119→          BigInt(agentId),
   120→          data.newWallet as `0x${string}`,
   121→          BigInt(data.deadline),
   122→          data.signature as `0x${string}`,
   123→        ],
   124→      });
   125→
   126→      setIsDelegated(true);
   127→      setStep("fund");
   128→    } catch (err) {
   129→      console.error("Delegation failed:", err);
   130→    } finally {
   131→      setDelegating(false);
   132→    }
   133→  };
   134→
   135→  const handleFund = async () => {
   136→    if (!agentAddress || !fundAmount) return;
   137→    const amount = parseFloat(fundAmount);
   138→    if (!amount || amount <= 0) return;
   139→
   140→    setFunding(true);
   141→    try {
   142→      await sendTransactionAsync({
   143→        to: agentAddress as `0x${string}`,
   144→        value: parseEther(fundAmount),
   145→      });
   146→      setFunded(true);
   147→      setStep("monitor");
   148→    } catch (err) {
   149→      console.error("Funding failed:", err);
   150→    } finally {
   151→      setFunding(false);
   152→    }
   153→  };
   154→
   155→  const currentIdx = STEPS.findIndex((x) => x.id === step);
   156→
   157→  if (!address) {
   158→    return (
   159→      <div className="mx-auto max-w-md text-center">
   160→        <h3 className="font-serif text-2xl text-ink">Connect your wallet.</h3>
   161→        <p className="mt-4 text-sm leading-relaxed text-ink-light">
   162→          Connect your wallet to deploy your autonomous agent and access
   163→          on-chain lending on Celo.
   164→        </p>
   165→      </div>
   166→    );
   167→  }
   168→
   169→  return (
   170→    <div className="space-y-12">
   171→      {/* Agent info bar */}
   172→      {agentAddress && (
   173→        <div className="flex items-center justify-between border-b border-cream-dark pb-4">
   174→          <div>
   175→            <span className={labelClass}>Agent Wallet</span>
   176→            <p className="mt-1 font-mono text-sm text-ink">
   177→              {agentAddress.slice(0, 6)}...{agentAddress.slice(-4)}
   178→            </p>
   179→          </div>
   180→          <div>
   181→            <span className={labelClass}>Network</span>
   182→            <p className="mt-1 font-mono text-sm text-ink">Celo</p>
   183→          </div>
   184→          <div>
   185→            <span className={labelClass}>Identity</span>
   186→            <p className="mt-1 font-mono text-sm text-ink">
   187→              {isDelegated
   188→                ? "Self (8004 SBT) — Delegated"
   189→                : isVerified
   190→                  ? "Self (8004 SBT)"
   191→                  : "Not verified"}
   192→            </p>
   193→          </div>
   194→          <div>
   195→            <span className={labelClass}>Status</span>
   196→            <p className="mt-1 font-mono text-sm text-ink">
   197→              {funded ? "Funded" : "Unfunded"}
   198→            </p>
   199→          </div>
   200→        </div>
   201→      )}
   202→
   203→      {/* Step indicator */}
   204→      <div className="flex items-center gap-3">
   205→        {STEPS.map((s, i) => {
   206→          const isDone = currentIdx > i;
   207→          const isCurrent = step === s.id;
   208→          return (
   209→            <div key={s.id} className="flex items-center gap-3">
   210→              <div className="flex items-center gap-2">
   211→                <span
   212→                  className={`font-mono text-xs ${isCurrent ? "text-ink" : isDone ? "text-ink-light" : "text-ink-lighter"}`}
   213→                >
   214→                  {isDone ? "\u2713" : `0${i + 1}`}
   215→                </span>
   216→                <button
   217→                  onClick={() => {
   218→                    if (isDone || isCurrent) setStep(s.id);
   219→                  }}
   220→                  disabled={!isDone && !isCurrent}
   221→                  className={`font-mono text-xs uppercase tracking-wider ${isCurrent ? "text-ink" : isDone ? "text-ink-light cursor-pointer hover:text-ink" : "text-ink-lighter"}`}
   222→                >
   223→                  {s.label}
   224→                </button>
   225→              </div>
   226→              {i < STEPS.length - 1 && (
   227→                <div className="h-px w-12 bg-cream-dark" />
   228→              )}
   229→            </div>
   230→          );
   231→        })}
   232→      </div>
   233→
   234→      {/* Step 1: Deploy Agent */}
   235→      {step === "deploy" && (
   236→        <div className="mx-auto max-w-md">
   237→          <h3 className="font-serif text-xl text-ink">Deploy your agent</h3>
   238→          <p className="mt-2 text-sm text-ink-light">
   239→            Deploy a Dockerized OpenClaw agent instance. Your connected wallet
   240→            serves as the human anchor for the agent lifecycle.
   241→          </p>
   242→
   243→          <div className="mt-6 space-y-4">
   244→            <div>
   245→              <label className={labelClass}>Agent Name</label>
   246→              <input
   247→                type="text"
   248→                value={agentName}
   249→                onChange={(e) => setAgentName(e.target.value)}
   250→                placeholder="my-agent"
   251→                className={inputClass}
   252→              />
   253→            </div>
   254→
   255→            <button
   256→              onClick={handleDeploy}
   257→              disabled={deploying || !agentName.trim()}
   258→              className="w-full bg-ink px-8 py-4 font-mono text-sm uppercase tracking-wider text-cream transition-opacity hover:opacity-80 disabled:opacity-30"
   259→            >
   260→              {deploying ? "Deploying..." : "Deploy Agent"}
   261→            </button>
   262→          </div>
   263→
   264→          <p className="mt-4 text-xs text-ink-lighter">
   265→            Human wallet: {address.slice(0, 6)}...{address.slice(-4)}
   266→          </p>
   267→        </div>
   268→      )}
   269→
   270→      {/* Step 2: Verify Identity */}
   271→      {step === "verify" && (
   272→        <div className="mx-auto max-w-md">
   273→          <SelfVerification
   274→            walletAddress={address}
   275→            onSuccess={handleVerificationSuccess}
   276→          />
   277→
   278→          {/* Skip verification */}
   279→          <div className="mt-8 border-t border-cream-dark pt-6">
   280→            <button
   281→              onClick={() => setStep("fund")}
