   285→            </button>
   286→          </div>
   287→        </div>
   288→      )}
   289→
   290→      {/* Step 3: Delegate Identity to Agent Wallet */}
   291→      {step === "delegate" && (
   292→        <div className="mx-auto max-w-md">
   293→          <h3 className="font-serif text-xl text-ink">
   294→            Delegate identity to agent
   295→          </h3>
   296→          <p className="mt-2 text-sm text-ink-light">
   297→            Link your Self-verified identity (Agent ID #{agentId}) to your
   298→            agent&apos;s wallet. This calls{" "}
   299→            <span className="font-mono">setAgentWallet</span> on the Self
   300→            registry so the agent can prove it&apos;s human-backed on-chain.
   301→          </p>
   302→
   303→          <div className="mt-6 space-y-4">
   304→            <div className="space-y-3 rounded border border-cream-dark bg-cream px-4 py-3">
