   306→                <span className="text-ink-lighter">Self Agent ID</span>
   307→                <span className="text-ink">#{agentId}</span>
   308→              </div>
   309→              <div className="flex justify-between font-mono text-sm">
   310→                <span className="text-ink-lighter">Agent Wallet (7702)</span>
   311→                <span className="text-ink">
   312→                  {agentAddress
   313→                    ? `${agentAddress.slice(0, 6)}...${agentAddress.slice(-4)}`
   314→                    : "—"}
   315→                </span>
   316→              </div>
   317→            </div>
   318→
   319→            <button
   320→              onClick={handleDelegate}
